ce  -->\n\nCoreModule->PrismaService \n\n\n\n\n\nVKIDModule\n\nVKIDModule\n\nAppModule -->\n\nVKIDModule->AppModule\n\n\n\n\n\nVKIDService \n\nVKIDService \n\nVKIDService  -->\n\nVKIDModule->VKIDService \n\n\n\n\n\nAuthService\n\nAuthService\n\nAuthModule -->\n\nAuthService->AuthModule\n\n\n\n\n\nJwtStrategy\n\nJwtStrategy\n\nAuthModule -->\n\nJwtStrategy->AuthModule\n\n\n\n\n\nLocalStrategy\n\nLocalStrategy\n\nAuthModule -->\n\nLocalStrategy->AuthModule\n\n\n\n\n\nRefreshStrategy\n\nRefreshStrategy\n\nAuthModule -->\n\nRefreshStrategy->AuthModule\n\n\n\n\n\nTokenService\n\nTokenService\n\nAuthModule -->\n\nTokenService->AuthModule\n\n\n\n\n\nVKIDService\n\nVKIDService\n\nAuthModule -->\n\nVKIDService->AuthModule\n\n\n\nVKIDModule -->\n\nVKIDService->VKIDModule\n\n\n\n\n\nVKIDStrategy\n\nVKIDStrategy\n\nAuthModule -->\n\nVKIDStrategy->AuthModule\n\n\n\n\n\nConfigService \n\nConfigService \n\n\n\nConfigModule\n\nConfigModule\n\nCoreModule -->\n\nConfigModule->CoreModule\n\n\n\nConfigService  -->\n\nConfigModule->ConfigService \n\n\n\n\n\nAppConfigService\n\nAppConfigService\n\nCoreModule -->\n\nAppConfigService->CoreModule\n\n\n\nConfigModule -->\n\nAppConfigService->ConfigModule\n\n\n\n\n\nConfigService\n\nConfigService\n\nConfigModule -->\n\nConfigService->ConfigModule\n\n\n\n\n\nUploadRepository\n\nUploadRepository\n\nUploadModule -->\n\nUploadRepository->UploadModule\n\n\n\n\n\nUploadService\n\nUploadService\n\nUploadModule -->\n\nUploadService->UploadModule\n\n\n\n\n\n\n    \n    \n    \n        Zoom in\n        Reset\n        Zoom out\n    \n\n  \n\n    \n        \n            \n                \n                    \n                    \n                        7 Modules\n                    \n                \n            \n        \n        \n            \n                \n                    \n                    5 Controllers\n                \n            \n        \n        \n            \n                \n                    \n                    18 